options.script:
var suites = {};
var scenarioMap = {};

data.series.forEach(function(frame) {
  var refId = frame.refId || 'A';
  var valueField = null;
  var suite_id = null;
  var scenario_id = null;

  frame.fields.forEach(function(field) {
    if (field.labels) {
      if (field.labels.suite_id) suite_id = field.labels.suite_id;
      if (field.labels.scenario_id) scenario_id = field.labels.scenario_id;
    }
    if (field.type === 'number' && field.values && field.values.length > 0) {
      valueField = field.values[field.values.length - 1];
    }
  });

  if (!suite_id || !scenario_id || valueField == null) return;

  var key = suite_id + '|' + scenario_id;
  suites[suite_id] = true;
  if (!scenarioMap[key]) {
    scenarioMap[key] = { suite_id: suite_id, scenario_id: scenario_id };
  }
  if (refId === 'A') {
    scenarioMap[key].success_rate = valueField;
  } else {
    scenarioMap[key].runs = valueField;
  }
});

var labels = ['전체'];
var parents = [''];
var values = [0];
var markerColors = ['rgba(0,0,0,0)'];
var texts = [''];

Object.keys(suites).forEach(function(suite) {
  labels.push(suite);
  parents.push('전체');
  values.push(0);
  markerColors.push('rgba(100,100,200,0.3)');
  texts.push(suite);
});

Object.keys(scenarioMap).forEach(function(key) {
  var sc = scenarioMap[key];
  var runs = sc.runs || 1;
  var sr = sc.success_rate != null ? sc.success_rate : -1;
  var color;
  if (sr < 0) { color = 'grey'; }
  else if (sr < 0.5) { color = '#F2495C'; }
  else if (sr < 0.7) { color = '#FF9830'; }
  else { color = '#73BF69'; }
  labels.push(sc.scenario_id);
  parents.push(sc.suite_id);
  values.push(runs);
  markerColors.push(color);
  var srText = sr >= 0 ? (sr * 100).toFixed(0) + '%' : 'N/A';
  texts.push(sc.scenario_id + '<br>실행: ' + runs + '회<br>성공률: ' + srText);
});

return {
  data: [{
    type: 'treemap',
    labels: labels,
    parents: parents,
    values: values,
    marker: { colors: markerColors },
    text: texts,
    hovertemplate: '%{text}<extra></extra>',
    textinfo: 'label',
    branchvalues: 'remainder'
  }],
  layout: {
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    font: { color: '#d8d9da', size: 11 },
    margin: { t: 10, b: 10, l: 10, r: 10 }
  },
  config: { responsive: true }
};
